            let current_fn = ctx.function();
            let entry_bb = ctx.builder().get_insert_block().or_internal("no insert block")?;
            let loop_bb = ctx.llvm_context().append_basic_block(current_fn, "idxof_loop");
            let body_bb = ctx.llvm_context().append_basic_block(current_fn, "idxof_body");
            let inc_bb = ctx.llvm_context().append_basic_block(current_fn, "idxof_inc");
            let found_bb = ctx.llvm_context().append_basic_block(current_fn, "idxof_found");
            let not_found_bb = ctx.llvm_context().append_basic_block(current_fn, "idxof_not_found");
            let merge_bb = ctx.llvm_context().append_basic_block(current_fn, "idxof_merge");
            ctx.builder().build_unconditional_branch(loop_bb)
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            ctx.builder().position_at_end(loop_bb);
            let phi_i = ctx.builder().build_phi(i64_type, "i")
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            let i_val = phi_i.as_basic_value().into_int_value();
            let cmp_done = ctx.builder().build_int_compare(
                IntPredicate::SLT, i_val, len, "cmp_done"
            ).map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            ctx.builder().build_conditional_branch(cmp_done, body_bb, not_found_bb)
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            ctx.builder().position_at_end(body_bb);
            // SAFETY: GEP into the list backing array to access element at loop index i; i is bounded by list length via the loop condition
            let elem_ptr = unsafe { ctx.builder().build_in_bounds_gep(
                i64_type, backing_ptr, &[i_val], "elem_ptr"
            ).map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))? };
            let elem = ctx.builder().build_load(i64_type, elem_ptr, "elem")
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?.into_int_value();
            let cmp_eq = ctx.builder().build_int_compare(
                IntPredicate::EQ, elem, search_val, "cmp_eq"
            ).map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            ctx.builder().build_conditional_branch(cmp_eq, found_bb, inc_bb)
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            // Increment: i++ → loop
            ctx.builder().position_at_end(inc_bb);
            let i_next = ctx.builder().build_int_add(
                i_val, i64_type.const_int(1, false), "i_next"
            ).map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            ctx.builder().build_unconditional_branch(loop_bb)
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            phi_i.add_incoming(&[(&i64_type.const_zero(), entry_bb), (&i_next, inc_bb)]);
            ctx.builder().position_at_end(found_bb);
            ctx.builder().build_unconditional_branch(merge_bb)
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            ctx.builder().position_at_end(not_found_bb);
            ctx.builder().build_unconditional_branch(merge_bb)
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            ctx.builder().position_at_end(merge_bb);
            let phi_result = ctx.builder().build_phi(i64_type, "idxof_result")
                .map_err(|e| LlvmLoweringError::llvm_error(e.to_string()))?;
            phi_result.add_incoming(&[
                (&i_val, found_bb),
                (&i64_type.const_int(u64::MAX, true), not_found_bb), // -1
            ]);
            ctx.set_register(dst.0, phi_result.as_basic_value());
